#include <algorithm>
#include <iostream>
#include <vector>

int main()
{
    int n{};
    int t{};
    std::cin >> n >> t;

    std::vector<int> v(n);
    for (int i{ 0 }; i < n; ++i)
        std::cin >> v[i];

    std::vector<int> diff(n);
    for (int i{ 0 }; i < n; ++i)
        diff[i] = v[i] - t;

    auto count{ std::count_if(diff.begin(), diff.end(),
        [](int x) { return x > 0; }) };

    std::cout << count << '\n';

    return 0;
}

